import java.util.*;class CircularTour{static int tour(int[] p,int[] d){int n=p.length,start=0,cur=0,def=0;for(int i=0;i<n;i++){cur+=p[i]-d[i];if(cur<0){start=i+1;def+=cur;cur=0;}}return cur+def>=0?start:-1;}public static void main(String[]a){Scanner s=new Scanner(System.in);int n=s.nextInt();int[] p=new int[n],d=new int[n];for(int i=0;i<n;i++){p[i]=s.nextInt();d[i]=s.nextInt();}System.out.println(tour(p,d));}}